{
    "title": "Each Other vs Reflexive Pronouns",
    "intro": "Comparison of reciprocal and reflexive pronouns:",
    "rows": [
        {
            "en": "They love <strong>each other</strong>.",
            "ua": "They love each other.",
            "note": "(He loves her + she loves him - mutual action)"
        },
        {
            "en": "She loves <strong>herself</strong>.",
            "ua": "She loves herself.",
            "note": "(Action on herself)"
        },
        {
            "en": "We see <strong>each other</strong> often.",
            "ua": "We see each other often one.",
            "note": "(Mutual action)"
        },
        {
            "en": "I see <strong>myself</strong> in the mirror.",
            "ua": "I see myself in the mirror.",
            "note": "(Action on self)"
        },
        {
            "en": "They hugged <strong>each other.",
            "ua": "Вони обійняли один одного.",
            "note": "(Взаємна дія)"
        },
        {
            "en": "He hurt <strong>himself</strong>.",
            "ua": "Він поранив себе.",
            "note": "(Дія на себе)"
        }
    ]
}
